// Parse digest output from Claude API format
const input = $input.first().json;
let digest;

try {
  const text = input.content[0].text;
  digest = JSON.parse(text);
} catch (e) {
  // Fallback if parsing fails
  digest = {
    executive_tldr: 'Failed to generate digest summary.',
    sections: [],
    emerging_patterns: [],
    looking_ahead: ['Review source insights manually'],
    insight_count: 0,
    top_topics: []
  };
}

const periodData = input._periodData;
const uniqueCitations = input._uniqueCitations || [];

// Build full markdown content for digest
let contentMarkdown = `---\nid: "${periodData.digestId}"\ntype: "weekly-digest"\npublished_at: "${new Date().toISOString()}"\nperiod_start: "${periodData.periodStartDisplay}"\nperiod_end: "${periodData.periodEndDisplay}"\ninsight_count: ${digest.insight_count}\n---\n\n`;

contentMarkdown += `# Weekly Freedom Tech Digest\n\n`;
contentMarkdown += `*${periodData.periodStartDisplay} to ${periodData.periodEndDisplay}*\n\n`;

contentMarkdown += `## TL;DR\n\n${digest.executive_tldr}\n\n`;

contentMarkdown += `## Top Signals\n\n`;
for (const section of digest.sections) {
  contentMarkdown += section.content_markdown + '\n';
}

if (digest.emerging_patterns && digest.emerging_patterns.length > 0) {
  contentMarkdown += `## Emerging Patterns\n\n`;
  for (const pattern of digest.emerging_patterns) {
    contentMarkdown += `- **${pattern.pattern}**\n`;
  }
  contentMarkdown += '\n';
}

if (digest.looking_ahead && digest.looking_ahead.length > 0) {
  contentMarkdown += `## Looking Ahead\n\n`;
  for (const item of digest.looking_ahead) {
    contentMarkdown += `- ${item}\n`;
  }
  contentMarkdown += '\n';
}

if (uniqueCitations && uniqueCitations.length > 0) {
  contentMarkdown += `## Sources This Week\n\n`;
  for (const citation of uniqueCitations.slice(0, 20)) {
    contentMarkdown += `- ${citation}\n`;
  }
}

// Prepare data for database insert
return [{
  json: {
    periodStart: periodData.periodStartDisplay,
    periodEnd: periodData.periodEndDisplay,
    insightCount: digest.insight_count,
    executiveTldr: digest.executive_tldr,
    contentMarkdown: contentMarkdown,
    topTopics: digest.top_topics || [],
    digestId: periodData.digestId
  }
}];

// Build INSERT query for digests table with proper escaping
const data = $input.first().json;

function escapeStr(str) {
  if (str === null || str === undefined) return 'NULL';
  return "'" + String(str).replace(/'/g, "''") + "'";
}

function formatPgArray(arr) {
  if (!arr || arr.length === 0) return "'{}'";
  const escaped = arr.map(s => '"' + String(s).replace(/"/g, '\\"').replace(/'/g, "''") + '"');
  return "'{" + escaped.join(',') + "}'";
}

const publishedAt = new Date().toISOString();
const publishedUrl = `https://libertas.fgu.tech/digests/${data.digestId}`;

const query = `INSERT INTO digests (
  period_start, period_end, insight_count, executive_tldr,
  content_markdown, top_topics, published_url, published_at
) VALUES (
  ${escapeStr(data.periodStart)}::date,
  ${escapeStr(data.periodEnd)}::date,
  ${data.insightCount},
  ${escapeStr(data.executiveTldr)},
  ${escapeStr(data.contentMarkdown)},
  ${formatPgArray(data.topTopics)},
  ${escapeStr(publishedUrl)},
  ${escapeStr(publishedAt)}::timestamptz
) ON CONFLICT (period_start, period_end) 
DO UPDATE SET
  insight_count = EXCLUDED.insight_count,
  executive_tldr = EXCLUDED.executive_tldr,
  content_markdown = EXCLUDED.content_markdown,
  top_topics = EXCLUDED.top_topics,
  published_url = EXCLUDED.published_url,
  published_at = EXCLUDED.published_at,
  updated_at = NOW()
RETURNING id, period_start, period_end, published_url`;

return [{ 
  json: { 
    query, 
    digestData: {
      ...data,
      publishedUrl,
      publishedAt
    }
  } 
}];

// Merge insert result with digest data
const insertResult = $input.first().json;
const digestData = $('Build Digest Query').first().json.digestData;

return [{
  json: {
    digestId: insertResult.id,
    periodStart: insertResult.period_start || digestData.periodStart,
    periodEnd: insertResult.period_end || digestData.periodEnd,
    publishedUrl: insertResult.published_url || digestData.publishedUrl,
    contentMarkdown: digestData.contentMarkdown,
    insightCount: digestData.insightCount,
    executiveTldr: digestData.executiveTldr
  }
}];

// STUB: GitHub commit for digest markdown
// Creates the markdown file content and simulates GitHub API response
// Replace with real HTTP Request to GitHub API when ready

const data = $input.first().json;

// Prepare file path and content for GitHub
const filePath = `site-content/posts/weekly/${data.periodEnd}.md`;
const fileContent = data.contentMarkdown;
const commitMessage = `Add weekly digest for ${data.periodStart} to ${data.periodEnd}`;

// Simulate successful GitHub commit response
return [{
  json: {
    success: true,
    commit: {
      sha: 'stub-sha-' + Date.now(),
      message: commitMessage
    },
    content: {
      path: filePath,
      sha: 'stub-file-sha-' + Date.now()
    },
    _digestData: data,
    _filePath: filePath,
    _commitMessage: commitMessage,
    _fileContentBase64: Buffer.from(fileContent).toString('base64')
  }
}];

// STUB: Send email via Resend
// Generates email content and simulates Resend API response
// Replace with real HTTP Request to Resend API when ready

const prevData = $input.first().json;
const digestData = prevData._digestData;

// Generate email HTML content
const emailHtml = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <style>
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; line-height: 1.6; color: #333; max-width: 600px; margin: 0 auto; padding: 20px; }
    h1 { color: #1a1a1a; border-bottom: 2px solid #f0f0f0; padding-bottom: 10px; }
    h2 { color: #444; margin-top: 30px; }
    .tldr { background: #f8f9fa; padding: 15px; border-left: 4px solid #007acc; margin: 20px 0; }
    .footer { margin-top: 40px; padding-top: 20px; border-top: 1px solid #eee; font-size: 12px; color: #666; }
    a { color: #007acc; }
  </style>
</head>
<body>
  <h1>Weekly Freedom Tech Digest</h1>
  <p><em>${digestData.periodStart} to ${digestData.periodEnd}</em></p>

  <div class="tldr">
    <strong>TL;DR:</strong> ${digestData.executiveTldr}
  </div>

  <p><strong>${digestData.insightCount}</strong> signals published this week.</p>

  <p><a href="${digestData.publishedUrl}">Read the full digest on the web &rarr;</a></p>

  <div class="footer">
    <p>You're receiving this because you subscribed to Libertas Freedom Tech updates.</p>
    <p><a href="https://libertas.fgu.tech">libertas.fgu.tech</a> | <a href="{{{unsubscribe}}}">Unsubscribe</a></p>
  </div>
</body>
</html>
`;

const emailSubject = `Freedom Tech Digest: ${digestData.periodStart} - ${digestData.periodEnd}`;

// Simulate Resend API response
return [{
  json: {
    success: true,
    id: 'stub-email-' + Date.now(),
    from: 'Libertas <digest@libertas.fgu.tech>',
    to: ['subscribers@libertas.fgu.tech'],
    subject: emailSubject,
    _emailHtml: emailHtml,
    _digestData: digestData,
    _resendPayload: {
      from: 'Libertas <digest@libertas.fgu.tech>',
      to: ['subscribers@libertas.fgu.tech'],
      subject: emailSubject,
      html: emailHtml
    }
  }
}];

// Final summary of workflow execution
const emailResult = $input.first().json;
const digestData = emailResult._digestData;

const summary = {
  executedAt: new Date().toISOString(),
  success: true,
  digest: {
    periodStart: digestData.periodStart,
    periodEnd: digestData.periodEnd,
    insightCount: digestData.insightCount,
    publishedUrl: digestData.publishedUrl
  },
  actions: {
    databaseInsert: 'completed',
    githubCommit: 'stub (enable for production)',
    emailSent: 'stub (enable for production)'
  }
};

console.log('Workflow B Summary:', JSON.stringify(summary, null, 2));

return [{ json: summary }];

// Handle case when no insights were published in the period
const data = $input.first().json;

console.log(`No insights published for period ${data.periodStartDisplay} to ${data.periodEndDisplay}. Skipping digest generation.`);

return [{
  json: {
    executedAt: new Date().toISOString(),
    success: true,
    skipped: true,
    reason: 'No published insights in period',
    period: {
      start: data.periodStartDisplay,
      end: data.periodEndDisplay
    }
  }
}];
